passwords = ["hi", "hello", "pass1234", "abc123"]

for pwd in passwords:
    if len(pwd) < 8:
        print(f"Skipping '{pwd}' — too short.")
        continue
    if any(char.isdigit() for char in pwd):
        print(f"Valid password found: {pwd}")
        break
else:
    print("No valid password found in the list.")
